    end)

    it("adjacent extended chars", function()
        config = vim.tbl_deep_extend("force", vim.deepcopy(default_config), {
            ---@diagnostic disable-next-line: missing-fields
            hints = {
                Caret = {
                    prio = 100,
                    text = "â",
