        -- hello

        local marks = {
            Zero = 1,
            Caret = 2,
            e = 3,
            w = 5,
            Dollar = 8,
        }

        local virtual_line = VirtLine.build(config, marks, 8, {})
        eq("0âe w  $", virtual_line[1][1])
    end)
end)

